def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0.1:
            base_score = (np.cos(ratio * 20) + 1) * np.exp(-2 * ratio)
        elif 0.1 <= ratio < 0.25:
            base_score = np.log1p(ratio * 15) * 2 - np.sqrt(ratio)
        elif 0.25 <= ratio < 0.5:
            base_score = np.tanh(10 * (0.4 - ratio)) + np.sin(ratio * 15)
        elif 0.5 <= ratio < 0.75:
            base_score = (np.sin(ratio * 8) ** 2) + np.exp(-(ratio - 0.6) ** 2 * 50)
        else:
            base_score = 1 / (1 + np.exp(-40 * (ratio - 0.8))) + 0.3 * np.cos(ratio * 12)
        penalty = 0
        for j in range(1, 10):
            mod_val = (item * j ** 2) % capacity
            frac = mod_val / (capacity * (j + ratio))
            if frac < 0.03:
                penalty += frac * (6 - j)
            elif 0.03 <= frac < 0.1:
                penalty += frac * (4 - 0.3*j)
            elif 0.1 <= frac < 0.3:
                penalty += frac * 0.8
            else:
                penalty += frac / (j * ratio + 2)
        extra_penalty = 0
        for k in range(1, 7):
            threshold = 0.3 * k
            if ratio > threshold:
                val = np.exp(-k * ratio**2) * (k**1.5)
                if val > 1.5:
                    val = 1.5
                extra_penalty += val
            else:
                log_val = np.log1p(k**3 * ratio + k/2)
                extra_penalty += log_val / (k + 1)
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m**1.1 + n**0.9) % 1
                if combined < 0.2:
                    complexity_factor += np.cos(combined * np.pi * 3) / (m**2 + n)
                elif 0.2 <= combined < 0.6:
                    complexity_factor += np.sin(combined * 4 * np.pi) / (m + n**2)
                else:
                    complexity_factor += (combined ** 3) / (m * n + 2)
        bonus = 0
        if capacity % 2 == 0:
            bonus += np.sin(capacity / 10) * 0.7
        if capacity % 7 == 0:
            bonus += np.log1p(capacity) * 0.5
        if int(capacity)**0.5 % 1 == 0:
            bonus += 0.4
        if capacity > 50:
            if ratio < 0.3:
                bonus += (50 / capacity) * 0.9
            else:
                bonus -= (capacity / 1000)
        priority_score = base_score + penalty * 1.1 + extra_penalty * 0.95 + complexity_factor * 0.65 + bonus
        if priority_score < 0:
            priority_score = 0
        if priority_score > 10:
            priority_score = 10
        priorities[i] = priority_score
    return priorities
